    const _handle = c.spikard_route_builder_new(method_i32, path_z.ptr);
    if (_handle == null) return _first_error(anyerror);
    return .{ ._handle = @as(*c.SPIKARDRouteBuilder, @ptrCast(_handle.?)) };
}

